  ('elementary-6f0ba476-moex-00118', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '銷售下列貨物或勞務之營業稅稅率，何者為零？', '["國際間之運輸", "供應之農田灌溉用水", "稻米、麵粉之銷售及碾米加工", "代銷印花稅票或郵票之勞務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00119', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依營業稅法及其相關規定，經營一般飲食小規模營業人之營業稅起徵點為每月銷售額多少萬元？', '["12萬元", "10萬元", "8萬元", "6萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00120', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '在我國內無固定營業場所的外國事業甲，由網際網路銷售電子勞務予國內自然人乙，則營業稅納稅義務 人為：', '["甲", "乙", "甲的代理人", "免徵"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00121', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於現行遺產稅及贈與稅稅率結構的敘述，下列何者錯誤？', '["遺產稅最高邊際稅率為20%", "贈與稅最低邊際稅率為10%", "兩者皆為累進稅率結構", "兩者皆有2個稅率級距"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00122', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '甲為經常居住在中華民國境內之國民，在民國113年3月贈與乙250萬元，9月贈與丙100萬元。與此例 有關之贈與稅，下列敘述何者錯誤？', '["甲為納稅義務人", "甲當年度的贈與尚未超過贈與免稅額", "贈與稅率為累進稅制", "甲應於稽徵機關送達核定納稅通知書之日起2個月內，繳清應納稅款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00123', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依土地稅法之規定，土地所有權人出售其自用住宅用地者，出售前幾年內，曾供營業使用或出租者，不適 用一生一次之優惠稅率？', '["5年", "1年", "2年", "3年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
